var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"어라? 이 침묵은 설마……?","JPN":"あれ？　この沈黙はまさか……？","ENG":"Huh? This silence...","TWN":"咦？這段沉默難道……？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하, 로터스 시니어님께서도 텔레파시 능력자인 겁니까?","JPN":"ははーん、ロータスのシニアさんもテレパシー能力者なんやな！","ENG":"A-ha, are you a telepath too, Senior of Lotus?","TWN":"啊哈，難道洛德斯的Senior也會心電感應嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"누, 누가 텔레파시 능력자라는 거야?!","JPN":"だ、誰がテレパシー能力者だっていうのよ！","ENG":"W-who are you calling a telepath?!","TWN":"誰、誰會心電感應啊？！"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그리고, 당신이 미리네인지 뭔지 무슨 상관인 건데?!","JPN":"あと、「ウチはオノデラ・マリや」ー？　だから何だって言うのよ！　いきなり現れて！","ENG":"And what does it matter if you're Mi Rinae or whatever?!","TWN":"還有誰管妳是不是叫宓璃奈？！"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아이고~","JPN":"いやぁ～","ENG":"Goodness.","TWN":"哎喲～"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"귀청 떨어지게 반응하는 걸 보니까, 성격 예민한 것도 딱 로터스의 시니어님이 맞네예.","JPN":"耳が痛いほどの返事を返すとことか、神経質そうなとこ見ると、ロータスのシニアさんに間違いないな。","ENG":"That eardrum-busting reaction fits the sensitive personality I heard about. You really are the Senior of Lotus.","TWN":"看你這反應這麼大，果然跟傳聞中的洛德斯Senior一樣性格很敏感。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"다시 소개할게요. 저는 쌤의 부탁을 받아서 여기 오게 된 미리네라 캅니다.","JPN":"改めて紹介させてもらうわ。ウチは先生に頼まれてここに来た、オノデラ・マリや。","ENG":"Lemme reintroduce myself. I'm Mi Rinae, here at Teach's request.","TWN":"我再自我介紹一次。我是受老師拜託，特地過來的宓璃奈。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"쌤……?","JPN":"先生……？","ENG":"Teach...?","TWN":"老師……？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥, 이 시간에 이렇게 찾아오는 사람이면 뻔하지.","JPN":"ふん、こんな時に突然やってくる人の正体なんて決まってる。","ENG":"Hmph, if someone shows up at this hour, isn't it obvious?","TWN":"哼，會在這種時間跑來的人不就只有那幾位嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자의 지시야?","JPN":"最高管理者の指示なんでしょ？","ENG":"Orders from the Supreme Administrator?","TWN":"是最高管理者的指示吧？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"역시! 쌤이 천재라 카더니 눈치도 빠르시네요.","JPN":"さすが！　先生が天才ゆうてただけあって察しがええね。","ENG":"As expected. Teach said you were a genius, and you are quick on the uptake.","TWN":"果然！老師說妳是天才，果然連反應都很快呢。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"맞아요. 이제 막 아마니 밸리에 도착했는데 서둘러 여기로 가라 안 캅니까?","JPN":"そうや。アマニーバレーに着いたとこやのに、はよ行け言われて……ホンマかなんわ。","ENG":"Right. I'd just arrived at Amani Valley when I was told to hurry here.","TWN":"沒錯。我才剛到阿瑪尼山谷，就被要求立刻趕來這裡。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"자, 이거 받으세요.","JPN":"じゃ、これ受け取ってな。","ENG":"Here, take this.","TWN":"來，這個給你。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이, 이건……?","JPN":"こ、これは……？","ENG":"W-what is this...?","TWN":"這、這是……？"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"황금 해골이로군요.","JPN":"黄金の骸骨ですね。","ENG":"A golden skull.","TWN":"是黃金骷髏呢。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래서, 이게 뭔데?","JPN":"で、これがどうしたの？","ENG":"So what is it?","TWN":"所以這到底是什麼？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That's...","TWN":"那個是……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그건 제가 설명해 드릴게요.","JPN":"それは私から説明します。","ENG":"\\"That, I'll explain.\\"","TWN":"由我來說明吧。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"제 이름은 시타 칸. 캄파멘토의 새로운 시니어예요.","JPN":"私の名前はシータ・カン。カンパメントの新しいシニアです。","ENG":"\\"My name is Sita Khan. I am the new Senior of Campamento.\\"","TWN":"我叫悉多坎，是坎帕門托的新任Senior。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"새로운 시니어라고?","JPN":"新しいシニア？","ENG":"The new Senior?","TWN":"新任Senior？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"잠깐, 그래서 둘 중 누가 시니어라는 거야?","JPN":"待って、シニアってどっち？","ENG":"Wait, which of you is the Senior then?","TWN":"等一下，所以這兩個人裡到底誰是Senior？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"왜 저 꼬마애가 말하면 당신이 이어받는 건데?","JPN":"なんで喋り始めたのはあの子なのに、続きはあなたが言うわけ？","ENG":"Why does the little one start talking and you finish for her?","TWN":"為什麼那小鬼說話後你就要接話？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"저, 저예요…….","JPN":"わ、私です……","ENG":"I-it is me...","TWN":"是、是我……。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하아, 뭔가 따지기엔 시간이 촉박하니까 그냥 넘어가자.","JPN":"はあ……色々突っ込みたいけど時間がないからやめとくよ。","ENG":"*Sigh* We're short on time, so I'll let it slide.","TWN":"唉，現在時間太緊急，沒空計較了。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"그 황금 유해는…….","JPN":"その黄金の遺骸は……","ENG":"Those golden remains are...","TWN":"那黃金遺骸是……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그 황금 유해는 할아버지께서 평생을 찾아 헤매던 황금향의 유산이에요.","JPN":"その黄金の遺骸は、おじいさまが生涯をかけて探した黄金郷の遺産なんです。","ENG":"\\"Those golden remains are the Golden Vale's Legacy my grandfather searched for all his life.\\"","TWN":"那黃金遺骸，是我爺爺畢生追尋的黃金鄉遺產。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"할아버지라고? 설마 칸 할아버지가……?","JPN":"おじいさま？　まさか、カンじいさんが……？","ENG":"Your grandfather? Do you mean Grandpa Khan...?","TWN":"爺爺？難道說坎爺爺他……？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"캄파멘토에서 무슨 일이 일어났냐면…….","JPN":"カンパメントで何が起きたかと言いますと……","ENG":"As for what happened in Campamento...","TWN":"坎帕門托發生的事是……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"그…….","JPN":"と……","ENG":"Well...","TWN":"那個……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그렇게 된 거예요.","JPN":"というわけです。","ENG":"That's how it went.","TWN":"就變成這樣了。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시, 실례지만 물 좀 마셔도 될까요?","JPN":"す、すみませんが、水を飲んでもいいでしょうか。","ENG":"E-excuse me, may I have some water?","TWN":"抱、抱歉，我能喝點水嗎……？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그렇구나… 칸 할아버지가…….","JPN":"そうか……あのカンじいさんが……","ENG":"I see... Grandpa Khan's...","TWN":"原來如此……坎爺爺他……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"지나치게 외향적인 사람이라 좀 부담스럽긴 했어도 정말 좋은 사람이었는데…….","JPN":"社交的すぎてちょっと苦手な部分はあったけど、本当にいい人だったのに……","ENG":"He was overly outgoing and a bit much at times, but he was truly a good person.","TWN":" 雖然他太外向讓人有點吃不消，但他人真的很好……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그럼 칸 할아버지가 찾아낸 그 유해가 공간을 안정시켜주는 아티팩트라는 말이지?","JPN":"じゃあ、カンじいさんが見つけたその遺骸が、空間を安定化させてくれるアーティファクトってわけ？","ENG":"So those remains he found are an Artifact that stabilizes space, right?","TWN":"所以坎爺爺找到的這個遺骸，是能讓空間穩來的古代遺物嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"네…….","JPN":"はい…","ENG":"Yes...","TWN":"對……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};